import{_ as a,o as e,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"2.1.建立人物卡以继续游戏","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/2.建卡相关/2.1.建立人物卡以继续游戏.md","filePath":"1.基础规则/2.建卡相关/2.1.建立人物卡以继续游戏.md"}'),_={name:"1.基础规则/2.建卡相关/2.1.建立人物卡以继续游戏.md"};function s(o,b,d,l,h,i){return e(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"_2-1-建立人物卡以继续游戏",tabindex:"-1"},[p("2.1.建立人物卡以继续游戏 "),r("a",{class:"header-anchor",href:"#_2-1-建立人物卡以继续游戏","aria-label":'Permalink to "2.1.建立人物卡以继续游戏"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001A")])])],-1),n('<h1 id="建立人物卡以继续游戏" tabindex="-1">建立人物卡以继续游戏 <a class="header-anchor" href="#建立人物卡以继续游戏" aria-label="Permalink to &quot;建立人物卡以继续游戏&quot;">​</a></h1><p>continued<br> 建立人物卡以继续游戏<br> 在建立人物卡的开始阶段，首先自然而然的需要一张人物卡（<a href="./2.2.范例空白卡.html">请参照后录</a>）<br> 无论如何，在建立一张人物卡时，都需要首先在意的是人物的设定而非强度，不要为了选择某些开卡方式而刻意去追求强度车卡，在娱乐游戏的基础上适当进行这一活动。<br> 关于人物姓名、种族、国籍、身高、体重等基础设定部分，本质上以建卡者喜好自行填写。<br> 概述部分填写人物背景，角色概念部分填写人物外观。</p><hr><p>建立人物卡-基础信息与背景阶段实例：</p><p><strong>姓名：克莱门斯·施密特<br> 性别：男<br> 年龄：17 <br> 身高/体重：176/47KG <br> 种族/国籍：德国<br> 语言：德语<br> 相貌：4<br> 性格/特征：沉默、孤僻 <br> 注意：一般情况下，性格/特征会被认为是扮演还原人物形象的第一直观表现，因此，对性格/特征的重视是扮演的第一环</strong></p><p>人物背景范例</p><p>**“你知道的，他们对我很不好，而且我也觉得这里并不是家。”<br> 少年对少女说，今天是他们毕业前的最后一天，无数匆匆人流从他们的身边穿过，走入学院之中，也有更多人抱着书本和学习用品走出这里，无论怎么说，他们终于是毕业了。<br> 少女并没直接回答他的话，而是将目光落在远处那些戴袖标的人身上，她不禁皱了皱眉，她一直讨厌他们，或许在这一点上她和他的观点惊人的一致，平日在学校中，眼前的这个瘦弱男孩没少被他们欺负。<br> “我知道，如果你想离开，我会支持你的选择。”<br> 尽管他们两个的表情很冷淡，但街头巷尾都充斥着乐观的情绪，人们都认为他们最好的时代要来了，事实上，大部分人都是这么认为的。<br> 不知道有人说了些什么，瞬间在人群中掀起一阵欢呼，他们爆发出热烈的掌声与笑声，那笑声听起来是如此的刺耳。<br> “好了，你叫我来就是为了和我说这些的？”<br> 少女的表情更冷了，也让她对面的少年有些忐忑不安，是啊，这样的名门大小姐，怎么会将时间浪费在他这种人身上。<br> 他只好斟酌再三后选择孤注一掷，那一刻，时间似乎也缓慢下来，最后凝固，过客匆匆，终究连人生中的惊鸿一瞥都没有，留不下一点涟漪。<br> “我拒绝。”<br> 她的话干脆利落，断绝了所有可能，无视了所有未来，她不是那些狂热的年轻人，也不是老掉牙，即将住进棺材里的腐朽顽固，她一向睿智、冷静。<br> “我知道了。”<br> 少年坦然接受了他早已预演千万遍的失败的事实，故作轻松的准备离去。<br> “在你走之前，给你个忠告。”<br> 少女的声音一如既往的冷，冷的他似乎掉入深不见底的冰窟之中。<br> “离开这里。”<br> 他没有转过身，也没有回头，只是压抑住肩膀的颤抖，勉强点了点头。<br> ……<br> 两个月后，第二次世界大战爆发，彼时的克莱门斯已举家迁往美国，而在抵达圣弗朗西斯科郊外的那个晚上，他翻出了毕业典礼上的同学册，一张纸条夹在最后一页，他颤抖着轻柔的展开这张纸条，上面只有短短几个单词。<br> “我知道的，克莱门斯，但我更希望你活下去，因为这是一场必败的战争。<br> ——爱你的，卡洛特·沃尔夫冈·冯·米夏尔。”<br> **</p><hr><p>在建卡前，需先选择是否启用天命，若选择启用，则以方式1进行开卡，天命内容详见2.8 天命一节。若不启用，则使用方式2进行开卡。</p><p>属性部分：<br> ▓▓生理属性<br> ■力量<br> ■敏捷<br> ■耐力<br> ▓▓心智属性<br> ■智力<br> ■感知<br> ■决心<br> ▓▓互动属性<br> ■风度<br> ■操控<br> ■沉着<br> 在建卡之初，便需将总共21点自由属性分配入其中，当分配结束时，若某一种属性上的等级仍为0，则这张卡在所有包含那种属性的检定均无法进行检定，自动视为失败且出目为0，直至那个属性上获得1级为止。在分配过程中，属性的最高等级不能超过5，当建卡时属性希望从4点提升至5点时，这次提升需要1点额外的自由属性。</p><p>▓▓▓▓技能<br> ▓▓生理系<br> ■运动<br> ■求生<br> ■射击<br> ■武技</p><p>▓▓心智系<br> ■学识<br> ■器用<br> ■手艺<br> ■专注</p><p>▓▓互动系<br> ■洞察<br> ■隐秘<br> ■表达<br> ■社交<br> 在建卡之初，便需将总共24点自由技能点及12点自由专业点分配入其中，当分配结束时，若某一种技能上的等级仍为0，则这张卡在所有包含那种技能的检定均无法进行检定，自动视为失败且出目为0，直至那个技能上获得1级为止。<br> 在分配过程中，任意技能的等级至多不能超过3级，任意一个技能在建卡时希望从2级升至3级时都需要1点额外的自由技能点。</p><p>建卡结束后，若仍然存在0属性或0技能，那么ST有权拒绝收卡。</p><p>在建卡结束后，<a href="./2.4.属性概述.html">属性</a>的购买为1级500点，<a href="./2.5.技能概述.html">技能</a>的购买为1级500点。</p><p>在分配技能后：若为方式1进行开卡，则获得6专长点以购买任意专长。若为方式2进行开卡，则获得9点专长点以购买任意专长；选择专长最基础的需求是符合人物特点以建卡。</p><p>在购买专长时，1级专长需以1点专长点购买，而2级专长需以3点专长点购买，其余参考<a href="./../5.强化规则/5.3.支线分数XP与金钱.html">支线分数XP与金钱</a>一节。</p><p>在分配完属性、技能、专业、专长后，按照范例空白卡上的公式计算衍生属性值，其正常成年人在建卡时体积视为5，并且无法超过5，未成年人可以视情况减少。（1体积=40cm）</p><p>* * *</p><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',20)])])}const m=a(_,[["render",s]]);export{f as __pageData,m as default};
